import hashlib
import secrets

import jwt
from flask import Flask, request, jsonify, g

app = Flask(__name__)

# Configuration
app.config["SECRET_KEY"] = os.environ.get("JWT_SECRET_KEY") or secrets.token_hex(32)
app.config["JWT_EXPIRATION_MINUTES"] = int(os.environ.get("JWT_EXPIRATION_MINUTES", "30"))
app.config["JWT_ALGORITHM"] = "HS256"
app.config["JWT_ISSUER"] = "flask-jwt-auth"

# In-memory user store (replace with a real database in production)
_users_db: dict[str, dict] = {}


def _hash_password(password: str, salt: str | None = None) -> tuple[str, str]:
    """Hash a password with a random salt using PBKDF2."""
    if salt is None:
        salt = secrets.token_hex(16)
    pw_hash = hashlib.pbkdf2_hmac(
        "sha256",
        password.encode("utf-8"),
        salt.encode("utf-8"),
        iterations=600_000,
    )
    return pw_hash.hex(), salt


def _verify_password(password: str, stored_hash: str, salt: str) -> bool:
    """Verify a password against a stored hash."""
    pw_hash, _ = _hash_password(password, salt)
    return secrets.compare_digest(pw_hash, stored_hash)


def _validate_username(username: str) -> str | None:
    """Return an error message if the username is invalid, else None."""
    if not username or not isinstance(username, str):
        return "Username is required."
    if len(username) < 3 or len(username) > 64:
        return "Username must be between 3 and 64 characters."
    if not re.match(r"^[a-zA-Z0-9_.-]+$", username):
        return "Username may only contain letters, digits, underscores, dots, and hyphens."
    return None


def _validate_password(password: str) -> str | None:
    """Return an error message if the password is invalid, else None."""
    if not password or not isinstance(password, str):
        return "Password is required."
    if len(password) < 8:
        return "Password must be at least 8 characters."
    if len(password) > 128:
        return "Password must not exceed 128 characters."
    return None


def _create_token(user_id: str) -> str:
    """Create a signed JWT for the given user."""
    now = datetime.datetime.now(datetime.timezone.utc)
    payload = {
        "sub": user_id,
        "iat": now,
        "exp": now + datetime.timedelta(minutes=app.config["JWT_EXPIRATION_MINUTES"]),
        "iss": app.config["JWT_ISSUER"],
        "jti": secrets.token_hex(16),
    }
    token = jwt.encode(payload, app.config["SECRET_KEY"], algorithm=app.config["JWT_ALGORITHM"])
    return token


def _decode_token(token: str) -> dict | None:
    """Decode and verify a JWT. Returns the payload or None on failure."""
    try:
        payload = jwt.decode(
            token,
            app.config["SECRET_KEY"],
            algorithms=[app.config["JWT_ALGORITHM"]],
            issuer=app.config["JWT_ISSUER"],
            options={
                "require": ["sub", "iat", "exp", "iss", "jti"],
            },
        )
        return payload
    except (jwt.ExpiredSignatureError, jwt.InvalidTokenError):
        return None


def token_required(f):
    """Decorator that protects a route with JWT authentication."""

    @functools.wraps(f)
    def decorated(*args, **kwargs):
        auth_header = request.headers.get("Authorization", "")
        if not auth_header.startswith("Bearer "):
            return jsonify({"error": "Missing or malformed Authorization header."}), 401

        token = auth_header[7:]
        payload = _decode_token(token)
        if payload is None:
            return jsonify({"error": "Invalid or expired token."}), 401

        user_id = payload.get("sub")
        if user_id not in _users_db:
            return jsonify({"error": "User no longer exists."}), 401

        g.current_user = user_id
        return f(*args, **kwargs)

    return decorated


